// n8n - Code node (JavaScript)

function pickFirst(...vals) {
  for (const v of vals) {
    if (v !== undefined && v !== null && String(v).trim() !== "") return v;
  }
  return undefined;
}

const currency = String($node["Ação"]?.json?.newFieldValue ?? "").trim();

const wh = $node["Fields webhook"]?.json ?? {};
const cardId = pickFirst(
  wh.cardId,
  wh.card_id,
  wh.card?.id,
  wh.data?.card?.id,
  wh.body?.card?.id,
  wh.data?.cardId,
  wh.data?.card_id
);

if (!cardId) {
  throw new Error('cardId não encontrado no nó "Fields webhook".');
}

const BRL_FIELDS = [
  "valor_base_saas_categoria_a_b_brl",
  "valor_base_saas_categoria_e_s_brl",
  "valor_base_saas_categoria_espa_os_brl",
  "valor_base_saas_categoria_hospedagem_brl",
  "valor_base_saas_categoria_outros_brl",
  "valor_de_base_brl",
  "valor_nominal_a_ser_descontado_brl",
  "valor_total_do_item_brl",
  "valor_total_do_item_com_descontos_brl",
  "valor_unit_rio_brl",
];

const USD_FIELDS = [
  "valor_base_saas_categoria_a_b_usd",
  "valor_base_saas_categoria_e_s_usd",
  "valor_base_saas_categoria_espa_os_usd",
  "valor_base_saas_categoria_hospedagem_usd",
  "valor_base_saas_categoria_outros_usd",
  "valor_de_base_usd",
  "valor_nominal_a_ser_descontado_usd",
  "valor_total_do_item_usd",
  "valor_total_do_item_com_descontos_usd",
  "valor_unit_rio_usd",
];

// Regra: se escolheu USD, limpa BRL; se escolheu BRL, limpa USD
let fieldsToClear = [];
if (currency === "USD - $") fieldsToClear = BRL_FIELDS;
else if (currency === "BRL - R$") fieldsToClear = USD_FIELDS;

if (fieldsToClear.length === 0) {
  return [{ json: { skip: true, reason: `newFieldValue inesperado: ${currency}`, cardId: String(cardId) } }];
}

// Para campos numéricos/moeda, "" costuma falhar; use 0.
// value no Pipefy é LISTA ([UndefinedInput]) :contentReference[oaicite:1]{index=1}
const CLEAR_VALUE = [0];

const body = `
mutation UpdateFieldsValues($nodeId: ID!, $values: [NodeFieldValueInput!]!) {
  updateFieldsValues(input: { nodeId: $nodeId, values: $values }) {
    success
    userErrors { message }
  }
}
`.trim();

const variables = {
  nodeId: String(cardId),
  values: fieldsToClear.map((fieldId) => ({
    fieldId,       // slug do campo :contentReference[oaicite:2]{index=2}
    value: CLEAR_VALUE,
    // operation: "replace" // opcional (default é replace) :contentReference[oaicite:3]{index=3}
  })),
};

return [
  {
    json: {
      body,           // STRING da mutation (use isso no GraphQL node)
      variables,      // objeto variables
      requestBody: {  // JSON pronto (use isso no HTTP Request)
        query: body,
        variables,
      },
      debug: { currency, cardId: String(cardId), fieldsToClear, clearValueUsed: CLEAR_VALUE },
    },
  },
];

parameters.query:
query GetCardFields($cardId: ID!) {
  card(id: $cardId) {
    id
    createdAt
    title
    pipe {
      id
    }
    current_phase {
      id
      name
    }
    fields {
      field {
        id
        label
        type
      }
      value
      report_value
      native_value
      array_value

      connectedRepoItems {
        __typename
        ... on PublicTableRecord {
          id
          title
          uuid
          url
        }
      }
    }
  }
}

