={{ (() => {
  const fields = $json.data?.card?.fields ?? [];

  const getFieldValue = (fieldId) => {
    const field = fields.find(f => f.field?.id === fieldId);
    return field?.value ?? field?.report_value ?? field?.native_value ?? '';
  };

  const repoItem = fields
    .flatMap(f => f.connectedRepoItems ?? [])
    .find(item => item?.url === 'https://app.pipefy.com/apollo_databases/306808931/records/1268859019');

  const nomeProduto = repoItem?.title ?? getFieldValue('tipo_de_item');
  const modeloCobranca = getFieldValue('modelo_de_cobran_a');
  const nomeCliente = getFieldValue('clientes_na_fatura');

  const createdAt = $json.data?.card?.createdAt;
  let dataFatura = '';
  if (createdAt) {
    const date = new Date(createdAt);
    const mes = date.toLocaleDateString('pt-BR', { month: 'long', timeZone: 'UTC' });
    const ano = date.toLocaleDateString('pt-BR', { year: 'numeric', timeZone: 'UTC' });
    dataFatura = `${mes}/${ano}`;
  }

  const pipeID = String($json.data?.card?.pipe?.id ?? '').trim();

  if (pipeID === '306662125') {
    return nomeCliente || $json.data?.card?.title || '';
  }

  if (pipeID === '306852209' || pipeID === '306859915') {
    return [nomeProduto, modeloCobranca].filter(Boolean).join(' - ');
  }

  if (pipeID === '306859731') {
    return [nomeCliente, dataFatura].filter(Boolean).join(' - ');
  }

  return `PIPE_NAO_MAPEADO: ${pipeID}`;
})() }}

